import { motion, AnimatePresence } from 'framer-motion';

// ─── Stagger children on mount ──────────────────────────────────────────────
export const staggerContainer = {
  hidden: {},
  show: { transition: { staggerChildren: 0.05 } },
};

export const staggerItem = {
  hidden: { opacity: 0, y: 8 },
  show: { opacity: 1, y: 0, transition: { duration: 0.2, ease: [0.4, 0, 0.2, 1] } },
};

// ─── Hover scale for cards ──────────────────────────────────────────────────
export const cardHover = {
  whileHover: { scale: 1.01, transition: { duration: 0.15 } },
  whileTap: { scale: 0.99 },
};

// ─── Button press ───────────────────────────────────────────────────────────
export const buttonPress = {
  whileTap: { scale: 0.97 },
};

// ─── Fade in on mount ───────────────────────────────────────────────────────
export const fadeIn = {
  initial: { opacity: 0 },
  animate: { opacity: 1 },
  transition: { duration: 0.2 },
};

// ─── Slide up on mount ──────────────────────────────────────────────────────
export const slideUp = {
  initial: { opacity: 0, y: 12 },
  animate: { opacity: 1, y: 0 },
  transition: { duration: 0.25, ease: 'easeOut' },
};

// ─── Tab content transition ─────────────────────────────────────────────────
export function TabContent({ children, activeKey }) {
  return (
    <AnimatePresence mode="wait">
      <motion.div
        key={activeKey}
        initial={{ opacity: 0, x: 8 }}
        animate={{ opacity: 1, x: 0 }}
        exit={{ opacity: 0, x: -8 }}
        transition={{ duration: 0.15 }}
      >
        {children}
      </motion.div>
    </AnimatePresence>
  );
}

// ─── List item for AnimatePresence (add/remove animation) ───────────────────
export const listItemVariants = {
  initial: { opacity: 0, height: 0, marginBottom: 0 },
  animate: { opacity: 1, height: 'auto', marginBottom: 8, transition: { duration: 0.2 } },
  exit: { opacity: 0, height: 0, marginBottom: 0, transition: { duration: 0.15 } },
};
